// ---------- Inputs ----------
const f = $json;                     // form fields (must be present on the same item)
const cfg = $json.config || {};      // injected by your Config Normalizer step

// ---------- Config (from Google Sheet) ----------
const TIMEZONE = cfg.timezone || 'America/Chicago';

// Convert "HH:MM" -> [HH, MM]
function hhmmParts(s) {
  const [h, m] = (s || '').toString().trim().split(':').map(n => parseInt(n, 10));
  return [isFinite(h) ? h : 9, isFinite(m) ? m : 0];
}
const OPEN  = hhmmParts(cfg.hours_open  || '09:00');
const CLOSE = hhmmParts(cfg.hours_close || '23:00');

// Tax rate comes as decimal (e.g., 0.065). Fallback 0.
const TAX_RATE = Number(cfg.tax_rate ?? 0) || 0;

// ---------- Helpers ----------
function nowInTZ(tz) {
  const d = new Date();
  return new Date(d.toLocaleString('en-US', { timeZone: tz }));
}
function minutes(date) { return date.getHours() * 60 + date.getMinutes(); }

// ---------- Hours Gate ----------
const ct = nowInTZ(TIMEZONE);
const openMin  = OPEN[0]  * 60 + OPEN[1];
const closeMin = CLOSE[0] * 60 + CLOSE[1];
const curMin   = minutes(ct);
const in_hours = (curMin >= openMin && curMin < closeMin);

// ---------- Price Map (cents) ----------
const PRICE = {
  // Subs ($13)
  "Cowboy Chik’n": 1300,
  "Philly Chsteek": 1300,
  "Chik’n Club Sub": 1300,
  "Chik’n Fried Chik’n": 1300,
  // Small Bites
  "Chik’n Poppers ($10)": 1000,
  "Korean Popper ($12)": 1200,
  "Dumpling Taco ($10)": 1000,
  "Rocktown Bourbon Bites ($12)": 1200,
  "Chik’n Sliders ($13)": 1300,
  // Fries
  "Loaded Bacon Fries ($13)": 1300,
  "Philly Fries ($13)": 1300,
  "Chik’n or Stek Fries ($13)": 1300,
  "Garlic Parm Fries ($14)": 1400,
  "Just Fries ($5)": 500,
  // Drinks
  "Water ($2)": 200,
  "Sea Moss Lemonade ($6)": 600
};

let items = [];
function pushIfSelected(nameKey, qtyKey) {
  const name = f[nameKey];
  const qty = parseInt(f[qtyKey] || '0', 10) || 0;
  if (name && qty > 0) {
    const priceKey = Object.keys(PRICE).find(k => k.startsWith(name));
    const amount = PRICE[priceKey] || 0;
    items.push({
      name,
      quantity: qty,
      base_price_money: { amount, currency: 'USD' }
    });
  }
}

pushIfSelected('sub_choice', 'sub_qty');
pushIfSelected('smallbite_choice', 'smallbite_qty');
pushIfSelected('fries_choice', 'fries_qty');

// Drinks (optional flavor suffix)
if (f.drink_type) {
  const qty = parseInt(f.drink_qty || '0', 10) || 0;
  if (qty > 0) {
    const name = f.drink_type;
    items.push({
      name: name + (f.lemonade_flavor ? ` – ${f.lemonade_flavor}` : ''),
      quantity: qty,
      base_price_money: { amount: PRICE[name] || 0, currency: 'USD' }
    });
  }
}

// ---------- Totals ----------
const subtotal = items.reduce((s, i) => s + i.base_price_money.amount * i.quantity, 0);
const tax      = Math.round(subtotal * TAX_RATE);
const total    = subtotal + tax;

// ---------- Return ----------
return {
  ...f,
  ct_iso: ct.toISOString(),
  in_hours,
  items,
  subtotal,
  tax,
  total,
  idempotency_key: $json.order_id || $uuid(),
  config: cfg, // keep config available to downstream nodes
};
